{
  "domain_analysis": {
    "business_context": "Parcel delivery logistics platform managing shipment lifecycle from creation through transit to delivery, with weight-based pricing tiers.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, with a defined weight and lifecycle state." },
      { "term": "Pickup Address", "definition": "The origin location where a parcel is collected. Required at shipment creation." },
      { "term": "Delivery Address", "definition": "The destination location where a parcel must be delivered. Required at shipment creation." },
      { "term": "Shipment State", "definition": "The lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered. Transitions are forward-only." },
      { "term": "Weight Bracket", "definition": "A pricing classification derived from shipment weight: Standard (0–10 kg), Heavy (10–50 kg), Freight (>50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — there is no route to plan, no parcel to move. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a null or empty pickup address OR delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are forward-only: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "State regression would corrupt operational tracking, billing, and driver dispatch. A parcel that has left the warehouse cannot logically return to 'pending' without a new business event (e.g., a return shipment).",
      "testable_assertion": "Transitioning a shipment from In Transit to Pending must be rejected. Transitioning from Delivered to any other state must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state — no further state changes are allowed.",
      "invariant": true,
      "invariant_justification": "Delivery is a physical finality: the parcel has been handed over. Mutating this state would break audit trails, trigger incorrect billing reversals, and misrepresent reality.",
      "testable_assertion": "Any state change attempted on a Delivered shipment must be rejected regardless of target state."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound represents a physical/operational hard limit (vehicle capacity, safety regulations). Violating this corrupts pricing and dispatch planning.",
      "testable_assertion": "Creating or updating a shipment with weight <= 0 or weight > 1000 must be rejected."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket classification: Standard = (0, 10] kg; Heavy = (10, 50] kg; Freight = (50, 1000] kg.",
      "invariant": false,
      "invariant_justification": "Bracket thresholds are a pricing policy — a VP could adjust them (e.g., move the Heavy threshold to 15 kg) without corrupting system state.",
      "testable_assertion": "A 10 kg shipment is classified Standard. A 10.01 kg shipment is classified Heavy. A 50 kg shipment is classified Heavy. A 50.01 kg shipment is classified Freight."
    },
    {
      "id": "BR-6",
      "rule": "A newly created shipment begins in the Pending state.",
      "invariant": true,
      "invariant_justification": "A shipment cannot be born in transit or delivered — it must be acknowledged and awaiting pickup first. This is foundational to the forward-only state machine.",
      "testable_assertion": "After successful creation, shipment state must equal Pending."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A valid pickup address, delivery address, and weight of 5 kg",
      "when": "A shipment is created",
      "then": "The shipment is persisted in Pending state with weight bracket Standard"
    },
    {
      "id": "AC-2",
      "given": "A shipment creation request missing a pickup address",
      "when": "The system validates the request",
      "then": "The request is rejected with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A shipment creation request missing a delivery address",
      "when": "The system validates the request",
      "then": "The request is rejected with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "The shipment is transitioned to In Transit",
      "then": "The state changes to In Transit successfully"
    },
    {
      "id": "AC-5",
      "given": "A shipment in In Transit state",
      "when": "An attempt is made to transition it back to Pending",
      "then": "The transition is rejected and the state remains In Transit"
    },
    {
      "id": "AC-6",
      "given": "A shipment in In Transit state",
      "when": "The shipment is transitioned to Delivered",
      "then": "The state changes to Delivered successfully"
    },
    {
      "id": "AC-7",
      "given": "A shipment in Delivered state",
      "when": "Any state change is attempted (to Pending or In Transit)",
      "then": "The transition is rejected and the state remains Delivered"
    },
    {
      "id": "AC-8",
      "given": "A shipment creation request with weight 0 kg",
      "when": "The system validates the request",
      "then": "The request is rejected with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A shipment creation request with weight 1001 kg",
      "when": "The system validates the request",
      "then": "The request is rejected with a validation error indicating weight exceeds 1000 kg limit"
    },
    {
      "id": "AC-10",
      "given": "A shipment creation request with weight -5 kg",
      "when": "The system validates the request",
      "then": "The request is rejected with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight exactly 10 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as Standard"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight 10.01 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as Heavy"
    },
    {
      "id": "AC-13",
      "given": "A shipment with weight exactly 50 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as Heavy"
    },
    {
      "id": "AC-14",
      "given": "A shipment with weight 50.01 kg",
      "when": "The weight bracket is calculated",
      "then": "The shipment is classified as Freight"
    },
    {
      "id": "AC-15",
      "given": "A shipment in Pending state",
      "when": "An attempt is made to transition directly to Delivered",
      "then": "The transition is rejected — shipments must pass through In Transit first"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight is exactly 10 kg (Standard/Heavy boundary)", "expected_behavior": "Classified as Standard — bracket is inclusive on upper bound for the lower tier." },
    { "scenario": "Weight is exactly 50 kg (Heavy/Freight boundary)", "expected_behavior": "Classified as Heavy — bracket is inclusive on upper bound for the lower tier." },
    { "scenario": "Weight is exactly 1000 kg", "expected_behavior": "Accepted and classified as Freight — 1000 kg is the maximum, not above it." },
    { "scenario": "Weight is a very small positive number (e.g., 0.001 kg)", "expected_behavior": "Accepted and classified as Standard — weight is positive and within bounds." },
    { "scenario": "Attempting Pending → Delivered (skipping In Transit)", "expected_behavior": "Rejected. The spec implies a linear state machine; skipping states violates the forward-only lifecycle." },
    { "scenario": "Attempting to modify pickup or delivery address after shipment is In Transit", "expected_behavior": "Spec does not address address mutability post-creation. Needs clarification." },
    { "scenario": "Attempting to modify weight after shipment is In Transit or Delivered", "expected_behavior": "Spec does not address weight mutability post-creation. If weight changes, bracket and pricing could be affected retroactively." },
    { "scenario": "Shipment created with weight as non-numeric input", "expected_behavior": "Rejected at validation layer. Weight must be a numeric value." }
  ],

  "business_impact": {
    "financial": "Correct weight bracket classification directly determines pricing. Misclassification means under- or over-charging customers. The 1000 kg cap protects against accepting shipments the fleet cannot physically handle.",
    "operational": "The forward-only state machine prevents dispatch confusion — once a driver is en route, operations cannot silently revert the shipment to pending. Terminal delivery state ensures warehouse and fleet resources are freed.",
    "user": "Customers get predictable lifecycle tracking (Pending → In Transit → Delivered) with no confusing regressions. Clear weight validation prevents failed bookings after the fact.",
    "risk": "Low risk if implemented faithfully. Primary risk is boundary ambiguity at weight bracket edges (off-by-one errors at 10 kg and 50 kg). Secondary risk is the unaddressed mutability of addresses and weight post-creation.",
    "stakeholders_affected": [
      { "group": "Customers (shippers)", "impact": "Directly affected by weight validation, bracket pricing, and shipment state visibility." },
      { "group": "Drivers / Couriers", "impact": "Rely on state machine integrity — In Transit means they have a job; Pending regression would cause confusion and wasted trips." },
      { "group": "Finance / Billing", "impact": "Depend on correct weight bracket assignment for accurate invoicing. Terminal Delivered state triggers billing finalization." },
      { "group": "Operations / Dispatch", "impact": "State machine governs resource allocation. Incorrect transitions would corrupt dispatch planning." },
      { "group": "Customer Support", "impact": "Clear, immutable delivery states reduce disputes. Ambiguity around address/weight changes post-creation may generate support tickets." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is clear on core lifecycle rules, weight constraints, and bracket definitions. However, it leaves several practical concerns unaddressed: address and weight mutability post-creation, whether Pending→Delivered skip is allowed, cancellation flows, and whether weight brackets are inclusive or exclusive at boundaries. The 'charge by weight bracket' language implies pricing but gives no actual pricing rules. Confidence is above average but not high due to these gaps.",
    "high_confidence_areas": [
      "Forward-only state machine (Pending → In Transit → Delivered)",
      "Delivered is terminal",
      "Weight must be positive and ≤ 1000 kg",
      "Both addresses required at creation",
      "Three weight brackets exist: Standard, Heavy, Freight"
    ],
    "low_confidence_areas": [
      "Exact boundary behavior at 10 kg and 50 kg (inclusive upper vs exclusive upper) — spec says '0-10' and '10-50' which is ambiguous at boundaries",
      "Whether Pending → Delivered skip is allowed or if In Transit is mandatory",
      "Whether addresses or weight can be modified after creation",
      "Cancellation or exception flows (lost, damaged, returned) are entirely absent"
    ],
    "assumptions": [
      "Weight bracket boundaries are inclusive on the lower tier (10 kg = Standard, 50 kg = Heavy) based on common pricing conventions",
      "Shipments must pass through In Transit before reaching Delivered — the linear ordering implies no state skipping",
      "Shipment starts in Pending state upon creation — not explicitly stated but implied by the state machine",
      "Weight is captured at creation time and is the basis for bracket classification"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Weight bracket boundaries are ambiguous. The spec says '0-10 kg is standard, 10-50 kg is heavy, over 50 kg is freight.' Does a 10 kg parcel fall into Standard or Heavy? Does a 50 kg parcel fall into Heavy or Freight? The ranges overlap at the boundary points.",
      "affected_stakeholders": ["Finance / Billing", "Customers (shippers)"],
      "options": [
        "A: Lower tier is inclusive on upper bound (10 kg = Standard, 50 kg = Heavy)",
        "B: Upper tier is inclusive on lower bound (10 kg = Heavy, 50 kg = Freight)",
        "C: Use exclusive upper bounds throughout: Standard = [0,10), Heavy = [10,50), Freight = [50,1000]"
      ],
      "recommendation": "Option A — standard industry convention is to include the boundary in the cheaper tier, which is more customer-friendly. But PM should confirm."
    },
    {
      "type": "ambiguity",
      "description": "Can a shipment skip In Transit and go directly from Pending to Delivered? The spec says 'once in transit, it cannot be sent back to pending' but does not explicitly define all valid transitions.",
      "affected_stakeholders": ["Operations / Dispatch", "Drivers / Couriers"],
      "options": [
        "A: Only allow Pending → In Transit → Delivered (strict linear progression)",
        "B: Allow Pending → Delivered for edge cases like local/same-building deliveries"
      ],
      "recommendation": "Option A — strict linear progression. A shipment that is 'delivered' without ever being 'in transit' breaks tracking expectations and audit trails."
    },
    {
      "type": "missing_context",
      "description": "No cancellation or exception states are defined. Real logistics operations need to handle lost parcels, damaged goods, customer cancellations, and refused deliveries. The current spec has no exit ramp before Delivered.",
      "affected_stakeholders": ["Customer Support", "Customers (shippers)", "Finance / Billing"],
      "options": [
        "A: Add Cancelled state reachable from Pending and In Transit",
        "B: Handle exceptions outside the core state machine (separate Claims/Returns bounded context)",
        "C: Defer — ship the happy path now and add exception handling later"
      ],
      "recommendation": "Option A for Cancelled from Pending at minimum. Option B for post-transit exceptions. This is critical for production but may be acceptable to defer for MVP."
    },
    {
      "type": "missing_context",
      "description": "Mutability of shipment attributes (addresses, weight) after creation is not specified. Can a customer correct a delivery address while the shipment is still Pending? Can weight be updated after weigh-in?",
      "affected_stakeholders": ["Customers (shippers)", "Operations / Dispatch", "Finance / Billing"],
      "options": [
        "A: All attributes immutable after creation",
        "B: Mutable while Pending, immutable once In Transit",
        "C: Address mutable until Delivered, weight immutable after creation"
      ],
      "recommendation": "Option B — allow corrections while Pending, lock down once the parcel is physically moving. PM should confirm."
    }
  ],

  "rejection_reasons": []
}

